#include<bits/stdc++.h>
using namespace std;
int main(){
	int n,q,a[3][6666];
    cin>>n>>q;
    for(int i=1; i<=n; i++) cin>>a[0][i];
    for(int i=1; i<=q; i++) {
        cin>>a[1][i]>>a[2][i];
        int h=pow(10,a[1][i]),min= 10000001;
        for(int j=1; j<=n; j++) if(a[0][j]%h==a[2][i]&&a[0][j]<min) min=a[0][j];
        if(min != 10000001) cout<<min<<endl;
        else cout<<-1<<endl; 
    }
    return 0;
}
